{\pard \ql \f0 \sa180 \li0 \fi0 This script provides an advanced chord voicing editor for MIDI within REAPER. https://forum.cockos.com/showthread.php?t=305655\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 1.\tx360\tab ADD CHORD (Triads, Sus, Dim, Aug)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 2.\tx360\tab ADD INTERVAL (Extensions)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 3.\tx360\tab CHORD VOICING (Inversions, Drops, Voice Leading + Glue)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 4.\tx360\tab SELECTION (Select All + Filter)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 5.\tx360\tab TOOLS (Octaves, Duplication, Glue)\par}
{\pard \ql \f0 \sa0 \li360 \fi-360 6.\tx360\tab HUMANIZE (Classic Buttons + Sliders)\sa180\par}
}

